class SourceCredentialsManager(Boto3ModelManager):
    service_name: str = "codebuild"

    def import_credentials(
        self,
        token: str,
        serverType: Literal[
            "GITHUB", "BITBUCKET", "GITHUB_ENTERPRISE", "GITLAB", "GITLAB_SELF_MANAGED"
        ],
        authType: Literal[
            "OAUTH",
            "BASIC_AUTH",
            "PERSONAL_ACCESS_TOKEN",
            "CODECONNECTIONS",
            "SECRETS_MANAGER",
        ],
        *,
        username: "str | None" = None,
        shouldOverwrite: "bool | None" = None,
    ) -> str:
        """
        Imports the source repository credentials for an CodeBuild project that has its
        source code stored in a GitHub, GitHub Enterprise, GitLab, GitLab Self Managed,
        or Bitbucket repository.

        Args:
            token: For GitHub or GitHub Enterprise, this is the personal access token.
                For Bitbucket, this is either the access
                token or the app password. For the ``authType`` CODECONNECTIONS, this is
                the ``connectionArn``. For the ``authType``
                SECRETS_MANAGER, this is the ``secretArn``.
            serverType: The source provider used for this project.
            authType: The type of authentication used to connect to a GitHub, GitHub
                Enterprise, GitLab, GitLab Self Managed, or
                Bitbucket repository. An OAUTH connection is not supported by the API
                and must be created using the CodeBuild
                console.

        Keyword Args:
            username: The Bitbucket username when the ``authType`` is BASIC_AUTH. This
                parameter is not valid for other types of
                source providers or connections.
            shouldOverwrite: Set to ``false`` to prevent overwriting the repository
                source credentials. Set to ``true`` to
                overwrite the repository source credentials. The default value is
                ``true``.
        """
        args: dict[str, Any] = dict(
            token=self.serialize(token),
            serverType=self.serialize(serverType),
            authType=self.serialize(authType),
            username=self.serialize(username),
            shouldOverwrite=self.serialize(shouldOverwrite),
        )
        _response = self.client.import_source_credentials(
            **{k: v for k, v in args.items() if v is not None}
        )
        response = ImportSourceCredentialsOutput(**_response)

        results: str = None
        if response is not None:
            results = response.arn

        self.sessionize(results)
        return cast("str", results)

